// src/components/OdontogramaAvancado.jsx
import React, { useEffect, useRef } from "react";
import axios from "axios";

// ... (OdontoQuadrado, getSvgDente, quadrantes igual ao exemplo anterior)

export default function OdontogramaAvancado({
  pacienteId,
  denteSelecionado,
  setDenteSelecionado,
  facesSelecionadas,
  setFacesSelecionadas,
  tipoDente,
  setTipoDente
}) {
  const odontogramaCarregado = useRef(false);

  // Carrega do backend ao trocar paciente
  useEffect(() => {
    if (!pacienteId) return;
    odontogramaCarregado.current = false;
    axios.get(`/api/odontograma/paciente/${pacienteId}`).then(res => {
      const faces = {};
      const tipos = {};
      for (const od of res.data) {
        faces[od.dente] = od.faces || {};
        tipos[od.dente] = od.tipo_dente || "normal";
      }
      setFacesSelecionadas(faces);
      setTipoDente(tipos);
      odontogramaCarregado.current = true;
    });
  }, [pacienteId, setFacesSelecionadas, setTipoDente]);

  // Salva/upserta um dente ao alterar faces ou tipo
  function salvarNoBackend(dente, newFaces, newTipoDente) {
    if (!pacienteId || !odontogramaCarregado.current) return;
    axios.post('/api/odontograma', {
      paciente_id: pacienteId,
      dente,
      faces: newFaces,
      tipo_dente: newTipoDente
      // alterado_por: id do usuário logado (adicione se desejar)
    });
  }

  function handleToggleFace(num, face) {
    setFacesSelecionadas(fs => {
      const next = {
        ...fs,
        [num]: {
          ...fs[num],
          [face]: !fs[num]?.[face]
        }
      };
      salvarNoBackend(num, next[num], tipoDente[num] || "normal");
      return next;
    });
  }

  function handleToggleTipo(num, tipo) {
    setTipoDente(td => {
      const nextTipo = {
        ...td,
        [num]: td[num] === tipo ? "normal" : tipo
      };
      salvarNoBackend(num, facesSelecionadas[num] || {}, nextTipo[num]);
      return nextTipo;
    });


  // (renderQuadrante igual ao exemplo anterior, mas passe handleToggleFace no facesHandler)

  // ... Renderize quadrantes, botões, etc.
}


  // Altere seu PaginaTratamento para passar também setTipoDente ao OdontogramaAvancado

  return (
    <div className="w-full max-w-6xl mx-auto p-2 bg-white rounded-xl shadow">
      <div className="text-lg font-bold text-center mb-4">Odontograma</div>
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 w-full justify-center items-center">
        <div>
          <div className="text-center text-xs font-semibold text-gray-500 mb-1">Quadrante 1</div>
          {renderQuadrante({
            arr: Q_SUP_DIR,
            facesSelecionadas,
            denteSelecionado,
            setDenteSelecionado,
            tipoDente,
            facesHandler: handleToggleFace
          })}
        </div>
        <div>
          <div className="text-center text-xs font-semibold text-gray-500 mb-1">Quadrante 2</div>
          {renderQuadrante({
            arr: Q_SUP_ESQ,
            facesSelecionadas,
            denteSelecionado,
            setDenteSelecionado,
            tipoDente,
            facesHandler: handleToggleFace
          })}
        </div>
        <div>
          <div className="text-center text-xs font-semibold text-gray-500 mb-1">Quadrante 4</div>
          {renderQuadrante({
            arr: Q_INF_DIR,
            facesSelecionadas,
            denteSelecionado,
            setDenteSelecionado,
            tipoDente,
            facesHandler: handleToggleFace
          })}
        </div>
        <div>
          <div className="text-center text-xs font-semibold text-gray-500 mb-1">Quadrante 3</div>
          {renderQuadrante({
            arr: Q_INF_ESQ,
            facesSelecionadas,
            denteSelecionado,
            setDenteSelecionado,
            tipoDente,
            facesHandler: handleToggleFace
          })}
        </div>
      </div>
      <div className="flex flex-wrap gap-6 mt-6 justify-center text-sm">
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-orange-400 border border-gray-400" /> Selecionado
        </div>
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-gray-300 border border-gray-400" /> Não selecionado
        </div>
      </div>
    </div>
  );
}
